def _resolve_dynamic_option_defaults(command: Command, ctx: Context) -> None:
    """Resolve ``Option`` defaults that are specified as a dynamic
    mapping of other option values, e.g.
    ``default={"--protocol": {"http": 80, "https": 443}}``.

    This runs after all command line arguments, environment variables,
    and configuration files have been processed, so the values of the
    referenced options are final. It only overrides parameters whose
    source is still :attr:`ParameterSource.DEFAULT`.
    """
    params = command.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for source_opt, mapping in param.default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if isinstance(p, Option) and source_opt in p.opts
                ),
                None,
            )

            if source_param is None:
                continue

            source_value = ctx.params.get(source_param.name)  # type: ignore[arg-type]
            key = str(source_value)

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = resolved  # type: ignore[index]


